export function renderPrototypeVault(root, { items, capacity, overflowCount = 0, onFavorite = () => {}, onDismantle = () => {} }) {
  root.innerHTML = `<section class="codex"><header>PROTOTYPE VAULT <b>${items.length}/${capacity} · OVERFLOW ${overflowCount}</b></header><div class="codex__filters"><input data-family placeholder="Familie"><input data-tag placeholder="Tag"><input data-rarity placeholder="Seltenheit"><input data-source placeholder="Herkunft"></div><div class="codex__grid">${items.length ? items.map(item => `<article><span>${item.rarity} · ${item.stability ?? "stable"}</span><h3>${item.name}</h3><p>${(item.tags ?? []).map(tag => tag.id ?? tag).join(" · ")}</p><button data-favorite="${item.instanceId}">${item.favorite ? "★" : "☆"}</button><button data-dismantle="${item.instanceId}" ${item.favorite ? "disabled" : ""}>Zerlegen</button></article>`).join("") : `<div class="vault-empty"><strong>VAULT LEER</strong><span>Extrahiere Prototypen aus Runs, um sie hier zu sichern.</span></div>`}</div></section>`;
  root.onclick = event => { const favorite = event.target.closest("[data-favorite]"); const dismantle = event.target.closest("[data-dismantle]"); if (favorite) onFavorite(favorite.dataset.favorite); if (dismantle) onDismantle(dismantle.dataset.dismantle); };
}
